  ('elementary-f29af906-moex-00573', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '受理訴願機關審酌事證後，認為訴願有理由，訴願機關之決定，下列何者錯誤？', '["逕為變更之決定", "發回原處分機關另為處分", "撤銷原處分之全部或一部", "為不受理之決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
