  ('elementary-f29af906-moex-00575', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '土地所有權人A因其所有之土地被依法徵收，A不服徵收處分而提起訴願；該土地之地上權人B如 欲參加訴願，下列敘述何者正確？', '["B僅是事實上之利害關係人，不得參加訴願", "B得以法律上利害關係人地位參加訴願", "B應以訴願人地位參與訴願程序", "A依法不得提起訴願，故B亦不得參與訴願"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00576', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '被徵收土地所有權人對於內政部所為之徵收處分如有不服，應如何救濟？', '["應先向主管機關提出異議，不服異議結果，始得提起訴願救濟", "應先向主管機關提出異議，不服異議結果，主管機關得提請地價評議委員會復議，不服復議結果 者，即得提起訴願救濟", "得直接提起訴願救濟", "應先向地價評議委員會提出異議，不服異議結果，即得提起訴願救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00577', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '開發者依國土計畫法規定取得使用許可後，違反國土計畫法規，而主管機關疏於執行時，下列有關 其爭訟之敘述，何者正確？', '["公益團體得經一定程序後向行政法院提起訴訟", "公益團體得以主管機關怠於執行職務之行為向普通法院提起訴訟", "受害人民得依法提起撤銷訴訟", "受害人民得提起一般給付訴訟請求執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
